async def call_llm_with_timeout(messages: list, timeout: float = 120.0):
    try:
        return await asyncio.wait_for(
            llm_client.complete(messages),
            timeout=timeout,
        )
    except asyncio.TimeoutError:
        raise AgentStepTimeoutError(f"LLM did not respond within {timeout}s")

async def safe_agent_step(task: str):
    client = httpx.AsyncClient()
    try:
        return await run_step(client, task)
    except asyncio.CancelledError:
        # Re-raise — do not swallow CancelledError
        raise
    finally:
        await client.aclose()  # always clean up

# Better: use 'async with' which handles this automatically
async def safe_agent_step_v2(task: str):
    async with httpx.AsyncClient() as client:
        return await run_step(client, task)

def handle_task_exception(loop, context):
    exception = context.get("exception")
    if exception:
        logger.error("Unhandled async exception", exc_info=exception)
    else:
        logger.error("Async error: %s", context["message"])

loop = asyncio.get_event_loop()
loop.set_exception_handler(handle_task_exception)
